    // Function to check if a subarray is stable
    auto isStable = [](const std::vector<long long>& sub) {
        long long currentGCD = sub[0];
        for (size_t i = 1; i < sub.size(); ++i) {
            currentGCD = gcd(currentGCD, sub[i]);
            if (currentGCD == 1) break;
